import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../services/auth';
import { updateInstructorProfile } from '../services/instructors';

const Profile = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState({});
  const [files, setFiles] = useState({ avatar: null, cv_file: null });
  const navigate = useNavigate();

  useEffect(() => {
    authService.getCurrentUser().then(res => {
      setUser(res);
      if (res?.instructor_profile) setEditData(res.instructor_profile);
    }).catch(console.error).finally(() => setLoading(false));
  }, []);

  const handleEditChange = (e) => {
    const val = e.target.files ? e.target.files[0] : e.target.value;
    if (e.target.files) setFiles({ ...files, [e.target.name]: val });
    else setEditData({ ...editData, [e.target.name]: val });
  };

  const handleSave = async () => {
    setLoading(true);
    try {
      const fd = new FormData();
      Object.entries(editData).forEach(([k, v]) => { if(v !== null && v !== undefined && k !== 'user') fd.append(k, v) });
      if (files.avatar) fd.append('avatar', files.avatar);
      if (files.cv_file) fd.append('cv_file', files.cv_file);
      
      await updateInstructorProfile(user.instructor_profile.id, fd);
      setIsEditing(false);
      const updatedUser = await authService.getCurrentUser();
      setUser(updatedUser);
    } catch (err) { console.error(err); alert('فشل حفظ التغييرات'); }
    finally { setLoading(false); }
  };

  if (loading) return <div style={s.center}>⏳ جاري التحميل...</div>;
  if (!user) return <div style={s.center} onClick={()=>navigate('/login')}>فشل التحميل - اضغط للتسجيل</div>;

  const initials = ((user.first_name?.[0]||'')+(user.last_name?.[0]||''))||user.email[0].toUpperCase();
  const fullName = [user.first_name, user.last_name].filter(Boolean).join(' ')||user.email;

  return (
    <div style={s.page}>
      <div style={s.container}>
        <div style={s.topCard}>
          <div style={s.avatarWrap}>
            <img src={user.instructor_profile?.avatar_url || null} alt="Avatar" style={{...s.avatar, ...(user.instructor_profile?.avatar_url?{}:{background:'#e94560',display:'flex',alignItems:'center',justifyContent:'center',fontSize:28,fontWeight:800,color:'#fff'})}}>
              {!user.instructor_profile?.avatar_url && initials}
            </img>
            <div style={s.avatarRing}/>
          </div>
          <div style={s.topInfo}>
            <h1 style={s.name}>{fullName}</h1>
            <p style={s.email}>{user.email}</p>
            <span style={user.is_instructor?s.badgeInstructor:s.badgeStudent}>{user.is_instructor?'🎓 مدرّس':'📚 طالب'}</span>
          </div>
          <button style={s.dashBtn} onClick={()=>navigate(user.is_instructor?'/dashboard/instructor':'/dashboard/student')}>لوحة التحكم ←</button>
        </div>

        {/* ✅ قسم تعديل بيانات الدكتور */}
        {user.is_instructor && (
          <div style={s.instructorCard}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
              <h3 style={s.sectionTitle}>🎓 الملف التعليمي</h3>
              {!isEditing ? <button style={s.editBtn} onClick={()=>setIsEditing(true)}>✏️ تعديل</button>
                : <div style={{display:'flex',gap:8}}>
                  <button style={{...s.editBtn,background:'transparent',border:'1px solid #e94560',color:'#e94560'}} onClick={()=>setIsEditing(false)}>إلغاء</button>
                  <button style={{...s.editBtn,background:'#e94560'}} onClick={handleSave} disabled={loading}>💾 حفظ</button>
                </div>
              }
            </div>

            {isEditing ? (
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12}}>
                <div style={s.field}><label style={s.label}>اللقب</label>
                  <select style={s.input} name="title" value={editData.title||'dr'} onChange={handleEditChange}>
                    <option value="dr">دكتور</option><option value="prof">أستاذ دكتور</option><option value="eng">مهندس</option><option value="mr">أستاذ</option>
                  </select></div>
                <div style={s.field}><label style={s.label}>القسم</label>
                  <input style={s.input} name="department" value={editData.department||''} onChange={handleEditChange} /></div>
                <div style={s.field}><label style={s.label}>الجامعة</label>
                  <input style={s.input} name="university" value={editData.university||''} onChange={handleEditChange} /></div>
                <div style={s.field}><label style={s.label}>ساعات المكتب</label>
                  <input style={s.input} name="office_hours" value={editData.office_hours||''} onChange={handleEditChange} /></div>
                <div style={{gridColumn:'1/-1'}}><label style={s.label}>نبذة</label>
                  <textarea style={{...s.input,minHeight:60,resize:'vertical'}} name="bio" value={editData.bio||''} onChange={handleEditChange} /></div>
                <div style={s.field}><label style={s.label}>تغيير الصورة</label>
                  <input type="file" style={s.input} accept="image/*" name="avatar" onChange={handleEditChange} /></div>
                <div style={s.field}><label style={s.label}>تغيير السيرة الذاتية</label>
                  <input type="file" style={s.input} accept=".pdf" name="cv_file" onChange={handleEditChange} /></div>
              </div>
            ) : (
              <>
                <p style={s.bio}>{editData.bio || 'لا توجد نبذة مضافة.'}</p>
                <div style={s.statsWrap}>
                  <span>🎓 {editData.title_label||editData.title}</span>
                  <span>🏛️ {editData.department||'—'}</span>
                  <span>🎓 {editData.university||'—'}</span>
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

